const data = $input.first().json;
const downServices = [];
for (const [service, stats] of Object.entries(data)) {
  if (stats.latestStatus === 'DOWN') {
    downServices.push(`${service} (Last seen down: ${stats.lastDown || 'unknown'})`);
  }
}
if (downServices.length > 0) {
  return [{ json: { downServices: downServices.join('\n'), count: downServices.length } }];
}
return [];
